import logging
from logging.handlers import TimedRotatingFileHandler

# Define the log configuration
LOG_FILE = 'app.log'
LOG_DIR = '/var/log/myapp'

# Create the log directory if it doesn't exist
import os
if not os.path.exists(LOG_DIR):
    os.makedirs(LOG_DIR)

# Set up logging configuration
logging.basicConfig(level=logging.DEBUG)
logger = logging.getLogger('my_app_logger')

# Configure file handler with log rotation and permissions
file_handler = TimedRotatingFileHandler(os.path.join(LOG_DIR, LOG_FILE), when='midnight', interval=1, backupCount=7)
file_handler.suffix = "%Y-%m-%d"
file_handler.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))
file_handler.setLevel(logging.DEBUG)

# Set file permissions
import stat
os.chmod(file_handler.baseFilename, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH)

# Add the file handler to the logger
logger.addHandler(file_handler)

# Example usage of logging
logger.info('This is an info message')
logger.error('This is an error message')